import React from 'react';
import '../styles/components/Projects.css';

function Projects() {
  const projects = [
    {
      category: 'Personal Project',
      title: 'Sepakung Village Website',
      description: 'Create a website for a village in central Java.',
      tech: ['HTML', 'CSS', 'JavaScript', 'PHP', 'MySQL'],
      github: 'https://github.com/yourusername/portfolio'
    },
    {
      category: 'Group Project',
      title: 'Aplikasi Absensi',
      description: 'Aplikasi mobile untuk sistem absensi kegiatan organisasi dengan QR Code.',
      tech: ['React Native', 'Firebase'],
      github: 'https://github.com/yourusername/absensi-app'
    },
    {
      category: 'Client Project',
      title: 'E-Commerce UMKM',
      description: 'Platform e-commerce untuk UMKM dengan fitur pembayaran dan manajemen produk.',
      tech: ['React', 'Express', 'PostgreSQL'],
      github: 'https://github.com/yourusername/ecommerce'
    },
    {
      category: 'Personal Project',
      title: 'Blog Platform',
      description: 'Platform blog sederhana dengan fitur CRUD dan markdown support.',
      tech: ['Next.js', 'MongoDB', 'Tailwind'],
      github: 'https://github.com/yourusername/blog'
    },
    {
      category: 'Group Project',
      title: 'Event Management System',
      description: 'Sistem manajemen event terintegrasi untuk keperluan organisasi kampus.',
      tech: ['Next.js', 'Prisma', 'MySQL'],
      github: 'https://github.com/yourusername/event-system'
    },
    {
      category: 'Client Project',
      title: 'Company Profile',
      description: 'Website company profile dengan desain profesional dan responsif.',
      tech: ['React', 'Tailwind', 'Firebase'],
      github: 'https://github.com/yourusername/company-profile'
    }
  ];

  return (
    <section id="projects" className="projects">
      <div className="container">
        <h2 className="section-title">My Projects</h2>
        
        <div className="projects-grid">
          {projects.map((project, index) => (
            <div key={index} className="project-card">
              <div className="project-header">
                <div>
                  <h3>{project.title}</h3>
                </div>
                <span className="project-category">{project.category}</span>
              </div>
              
              <p>{project.description}</p>
              
              <div className="project-tech">
                {project.tech.map((tech, i) => (
                  <span key={i} className="tech-tag">{tech}</span>
                ))}
              </div>
              
              <div className="project-links">
                <a href={project.github} target="_blank" rel="noopener noreferrer" className="project-link">
                  <span>💻</span> GitHub
                </a>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Projects;
